// Caller lookup against the Caller Database board (18413254159).
// One row per caller, so no sorting/aggregation needed — just read the matched row.
const items = $input.all();
const firstItem = items?.[0]?.json;

const notFound = { json: {
  call_inbound: {
    dynamic_variables: {
      caller_found: "false",
      is_returning_caller: "false",
      caller_name: "",
      caller_state: "",
      caller_type: "unknown",
      caller_email: "",
      app_refused: "false",
      last_call_summary: "",
      caller_tickets: "[]"
    }
  }
} };

if (!items || items.length === 0 || !firstItem || !firstItem.column_values) {
  return [notFound];
}

const get = (id) => firstItem.column_values?.find(c => c.id === id)?.text || '';

const callerName = get('text_mm2mrhy6');
const callerState = get('text_mm2majqv');
const callerEmail = get('text_mm33xp6z');
const callerPhone = get('phone_mm2m7bhz');
const lastCallSummary = get('text_mm3bvv8e');
const lastCallType = get('text_mm3bpvag');

// Derive caller_type from the most recent call type stored on the caller row.
let callerType = 'unknown';
if (['missed_clockout','missed_clockin','travel','incident','dd_hold',
     'income_letter','address_update','nurse_cancel','paystubs_sfc'].includes(lastCallType)) {
  callerType = 'caregiver';
} else if (lastCallType === 'prospect') {
  callerType = 'prospect';
}

return [{ json: {
  call_inbound: {
    dynamic_variables: {
      caller_found: "true",
      is_returning_caller: "true",
      caller_name: callerName,
      caller_state: callerState,
      caller_type: callerType,
      caller_phone: callerPhone,
      caller_email: callerEmail,
      app_refused: "false",
      last_call_summary: lastCallSummary,
    }
  }
}}];
